INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'buffalo'), 'N-1D', 'n-1d', 'Downtown/Regional Hub', 'This zone addresses the core of downtown Buffalo, facilitating substantial development with an intense mix of uses. It is designed for high-density, mixed-use environments.', NULL, NULL, 1000, 100, 0, 0, 0, 'No minimum off-street parking requirements citywide. Bicycle parking and accessible parking requirements apply.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'n-1d' AND z.city_id = (SELECT id FROM cities WHERE slug = 'buffalo') AND pu.name IN ('Civic Building', 'Commercial Block', 'Stacked Units (Multi-unit dwellings)', 'Tower', 'Retail & Service', 'Employment (Offices)') ON CONFLICT DO NOTHING;
